class Solution {
    findMaxSubstring(s) {
        const n = s.length;
        let left = 0, right = 0;
        const mp = new Map();
        let maxSize = -Infinity;

        while (right < n) {
            const ch = s[right];
            mp.set(ch, (mp.get(ch) || 0) + 1);

            while (mp.get(ch) > (ch.charCodeAt(0) - 'a'.charCodeAt(0) + 1)) {
                const leftChar = s[left];
                mp.set(leftChar, mp.get(leftChar) - 1);
                left++;
            }

            maxSize = Math.max(maxSize, right - left + 1);
            right++;
        }

        return maxSize;
    }
}
